function Write-TSxUILog {
    param(
        [Parameter(Mandatory = $true)]
        [string]$Message,
        [string]$Level = 'INFO'
    )
    $timestamp = Get-Date -Format 'yyyy-MM-dd HH:mm:ss'
    try {
        Add-Content -Path $Script:UILogFile -Value ("[{0}] [{1}] [User: {2}] {3}" -f $timestamp, $Level, $Script:UIRunUser, $Message) -ErrorAction Stop
    }
    catch {
        Write-Verbose ("Unable to write to UI log file {0}. Error: {1}" -f $Script:UILogFile, $_.Exception.Message)
    }
}

