$GridVMs.Add_CellFormatting({
    param($sender, $e)

    if ($e.RowIndex -lt 0 -or $e.ColumnIndex -lt 0) {
        return
    }

    $columnName = $sender.Columns[$e.ColumnIndex].Name
    if ($columnName -eq 'VMName') {
        return
    }

    $valueText = [string]$e.Value
    if ($valueText -eq 'Yes' -or $valueText -eq 'True') {
        $e.CellStyle.ForeColor = [System.Drawing.Color]::ForestGreen
        $e.CellStyle.SelectionBackColor = [System.Drawing.Color]::ForestGreen
        $e.CellStyle.SelectionForeColor = [System.Drawing.Color]::White
    }
    elseif ($valueText -eq 'No' -or $valueText -eq 'False') {
        $e.CellStyle.ForeColor = [System.Drawing.Color]::Firebrick
        $e.CellStyle.SelectionBackColor = [System.Drawing.Color]::Firebrick
        $e.CellStyle.SelectionForeColor = [System.Drawing.Color]::White
    }
})

