$ButtonEnable.Enabled = $false

function Update-TSxUIEnableButtonState {
    $selectedRows = @($GridVMs.SelectedRows)
    if ($selectedRows.Count -eq 0) {
        $ButtonEnable.Enabled = $false
        return
    }

    $hasRunningOrSnapshot = $false
    foreach ($row in $selectedRows) {
        $isRunningText = [string]$row.Cells['IsRunning'].Value
        $hasSnapshotText = [string]$row.Cells['HasSnapshot'].Value
        if ($isRunningText -eq 'Yes' -or $hasSnapshotText -eq 'Yes') {
            $hasRunningOrSnapshot = $true
            break
        }
    }

    $ButtonEnable.Enabled = (-not $hasRunningOrSnapshot)
}

function Connect-TSxUI {
    $credUser = if ($Script:SelectedCredential) { $Script:SelectedCredential.UserName } else { 'current user' }
    $mode = if ($CheckBoxPSRemoting.Checked) { 'PSRemoting' } else { 'DCOM' }
    Write-TSxUILog -Message ("Connect requested. Host: '{0}', Credential: '{1}', Mode: '{2}'" -f $TextBox1.Text, $credUser, $mode)
    $LabelStatus.Text = "Connecting..."
    $Form.Refresh()
    try {
        Write-Host "Connecting to $($TextBox1.Text) via $mode"

        $isLocal = ($TextBox1.Text -eq '.' -or
                    $TextBox1.Text -ieq 'localhost' -or
                    $TextBox1.Text -ieq $env:COMPUTERNAME)

        # Close any existing PSSession before creating a new one
        if ($Script:PSSession) {
            Remove-PSSession -Session $Script:PSSession -ErrorAction SilentlyContinue
            $Script:PSSession = $null
        }

        if ($CheckBoxPSRemoting.Checked) {
            # ── PSRemoting path ──────────────────────────────────────────────────
            if ($isLocal -and -not $Script:IsAdmin) {
                $LabelStatus.Text = "Not elevated"
                [void][System.Windows.Forms.MessageBox]::Show(
                    "Connecting to the local host via PSRemoting requires administrator rights.`r`nUse the 'Elevate (Admin)' button to restart as administrator.",
                    'Enable-TSxNestedHyperVVMUI',
                    [System.Windows.Forms.MessageBoxButtons]::OK,
                    [System.Windows.Forms.MessageBoxIcon]::Warning
                )
                return
            }

            $sessionParams = @{ ErrorAction = 'Stop' }
            if (-not $isLocal) {
                $sessionParams['ComputerName'] = $TextBox1.Text
                if ($Script:SelectedCredential) {
                    $sessionParams['Credential'] = $Script:SelectedCredential
                }
            }

            Write-TSxUILog -Message ("Creating PSSession to '{0}'" -f $TextBox1.Text)
            $Script:PSSession = New-PSSession @sessionParams

            $vmData = Invoke-Command -Session $Script:PSSession -ScriptBlock {
                $vms = Get-VM -ErrorAction Stop | Sort-Object Name
                foreach ($vm in $vms) {
                    $snapshots = @(Get-VMSnapshot -VMName $vm.Name -ErrorAction SilentlyContinue)
                    $proc = Get-VMProcessor -VMName $vm.Name -ErrorAction SilentlyContinue
                    [PSCustomObject]@{
                        Name        = $vm.Name
                        State       = [string]$vm.State
                        MemoryStart = [int64]$vm.MemoryStartup
                        HasSnapshot = ($snapshots.Count -gt 0)
                        NestedVirt  = [bool]($proc -and $proc.ExposeVirtualizationExtensions)
                    }
                }
            }

            $GridVMs.Rows.Clear()
            $eligibleCount = 0
            foreach ($vm in $vmData) {
                $isRunning = ($vm.State -eq 'Running')
                $isOff     = ($vm.State -eq 'Off')
                $lessThan4GB = ($vm.MemoryStart -lt 4GB)
                $canEnable = ($isOff -and -not $vm.HasSnapshot -and -not $lessThan4GB -and -not $vm.NestedVirt)
                if ($canEnable) { $eligibleCount++ }

                [void]$GridVMs.Rows.Add(
                    $vm.Name,
                    ($(if ($canEnable) { 'Yes' } else { 'No' })),
                    $vm.NestedVirt.ToString(),
                    ($(if ($isRunning) { 'Yes' } else { 'No' })),
                    ($(if ($vm.HasSnapshot) { 'Yes' } else { 'No' })),
                    ($(if ($lessThan4GB) { 'Yes' } else { 'No' }))
                )
            }

            Update-TSxUIEnableButtonState
            $LabelStatus.Text = "Connected [PSR]: $(@($vmData).Count) VM(s)`r`nEligible: $eligibleCount"
            Write-TSxUILog -Message ("PSRemoting connect succeeded. Loaded {0} VM(s) from host '{1}'" -f @($vmData).Count, $TextBox1.Text)

        } else {
            # ── DCOM / ComputerName path (original) ─────────────────────────────
            $uiCimSession = $null
            try {
                if (-not $isLocal -and $Script:SelectedCredential) {
                    Write-TSxUILog -Message ("Creating DCOM CIM session to '{0}' as '{1}'" -f $TextBox1.Text, $Script:SelectedCredential.UserName)
                    $sessionOption = New-CimSessionOption -Protocol Dcom
                    $uiCimSession = New-CimSession -ComputerName $TextBox1.Text `
                                                   -Credential $Script:SelectedCredential `
                                                   -SessionOption $sessionOption `
                                                   -ErrorAction Stop
                    $vms = Get-VM -CimSession $uiCimSession -ErrorAction Stop | Sort-Object -Property Name
                }
                else {
                    $getVmParams = @{ ErrorAction = 'Stop' }
                    if (-not $isLocal) {
                        $getVmParams['ComputerName'] = $TextBox1.Text
                    }
                    $vms = Get-VM @getVmParams | Sort-Object -Property Name
                }
                $GridVMs.Rows.Clear()
                $eligibleCount = 0
                foreach ($vm in $vms) {
                    $isRunning = ($vm.State -eq 'Running')
                    $isOff = ($vm.State -eq 'Off')

                    if ($uiCimSession) {
                        $snapshots = @(Get-VMSnapshot -CimSession $uiCimSession -VMName $vm.Name -ErrorAction SilentlyContinue)
                        $vmProcessor = Get-VMProcessor -CimSession $uiCimSession -VMName $vm.Name -ErrorAction SilentlyContinue
                    }
                    elseif (-not $isLocal) {
                        $snapshots = @(Get-VMSnapshot -ComputerName $TextBox1.Text -VMName $vm.Name -ErrorAction SilentlyContinue)
                        $vmProcessor = Get-VMProcessor -ComputerName $TextBox1.Text -VMName $vm.Name -ErrorAction SilentlyContinue
                    }
                    else {
                        $snapshots = @(Get-VMSnapshot -VMName $vm.Name -ErrorAction SilentlyContinue)
                        $vmProcessor = Get-VMProcessor -VMName $vm.Name -ErrorAction SilentlyContinue
                    }

                    $hasSnapshot = ($snapshots.Count -gt 0)
                    $lessThan4GB = ([int64]$vm.MemoryStartup -lt 4GB)
                    $nestedVirtualization = [bool]($vmProcessor -and $vmProcessor.ExposeVirtualizationExtensions)
                    $canEnable = ($isOff -and -not $hasSnapshot -and -not $lessThan4GB -and -not $nestedVirtualization)
                    if ($canEnable) {
                        $eligibleCount++
                    }

                    [void]$GridVMs.Rows.Add(
                        $vm.Name,
                        ($(if ($canEnable) { 'Yes' } else { 'No' })),
                        $nestedVirtualization.ToString(),
                        ($(if ($isRunning) { 'Yes' } else { 'No' })),
                        ($(if ($hasSnapshot) { 'Yes' } else { 'No' })),
                        ($(if ($lessThan4GB) { 'Yes' } else { 'No' }))
                    )
                }

                Update-TSxUIEnableButtonState
                $LabelStatus.Text = "Connected: $($vms.Count) VM(s)`r`nEligible: $eligibleCount"
                Write-TSxUILog -Message ("Connect succeeded. Loaded {0} VM(s) from host '{1}'" -f $vms.Count, $TextBox1.Text)
            }
            finally {
                if ($uiCimSession) {
                    Remove-CimSession -CimSession $uiCimSession -ErrorAction SilentlyContinue
                }
            }
        }
    }
    catch {
        $LabelStatus.Text = "Connect failed"
        Write-TSxUILog -Level 'ERROR' -Message ("Connect failed. Host: '{0}'. Exception: {1}" -f $TextBox1.Text, $_.Exception.ToString())
        [void][System.Windows.Forms.MessageBox]::Show(
            "Failed to connect to host '$($TextBox1.Text)'.`r`n$($_.Exception.Message)",
            'Enable-TSxNestedHyperVVMUI',
            [System.Windows.Forms.MessageBoxButtons]::OK,
            [System.Windows.Forms.MessageBoxIcon]::Error
        )
    }
}

function Set-TSxUICredential {
    try {
        $credential = Get-Credential -Message "Enter credentials for Hyper-V remote/local alternate access"
        if ($credential) {
            $Script:SelectedCredential = $credential
            $LabelCred.Text = "Credential: $($credential.UserName)"
            Write-TSxUILog -Message ("Credential set. User: '{0}'" -f $credential.UserName)
        }
        else {
            Write-TSxUILog -Message 'Credential prompt was dismissed without input.'
        }
    }
    catch {
        Write-TSxUILog -Level 'ERROR' -Message ("Failed to set credential. Exception: {0}" -f $_.Exception.ToString())
        [void][System.Windows.Forms.MessageBox]::Show(
            "Failed to set credential.`r`n$($_.Exception.Message)",
            'Enable-TSxNestedHyperVVMUI',
            [System.Windows.Forms.MessageBoxButtons]::OK,
            [System.Windows.Forms.MessageBoxIcon]::Error
        )
    }
}

function Clear-TSxUICredential {
    Write-TSxUILog -Message 'Credential cleared. Reverting to current user context.'
    $Script:SelectedCredential = $null
    $LabelCred.Text = 'Credential: Current user'
}

function Manage-TSxUICredential {
    if ($Script:SelectedCredential) {
        $choice = [System.Windows.Forms.MessageBox]::Show(
            "A credential is already set: $($Script:SelectedCredential.UserName)`r`n`r`nYes = Change credential`r`nNo = Clear and use current user`r`nCancel = Keep current",
            'Enable-TSxNestedHyperVVMUI',
            [System.Windows.Forms.MessageBoxButtons]::YesNoCancel,
            [System.Windows.Forms.MessageBoxIcon]::Question
        )

        switch ($choice) {
            'Yes' { Set-TSxUICredential }
            'No'  { Clear-TSxUICredential }
            default { }
        }
        return
    }

    Set-TSxUICredential
}

function Close-TSxUI {
    $Form.Close()
}

function Enable-TSxUI {
    if (-not (Test-Path -Path $Script:NestedToolPath)) {
        Write-TSxUILog -Level 'ERROR' -Message ("Backend script not found: '{0}'" -f $Script:NestedToolPath)
        [void][System.Windows.Forms.MessageBox]::Show(
            "Cannot find wrapper target script:`r`n$Script:NestedToolPath",
            'Enable-TSxNestedHyperVVMUI',
            [System.Windows.Forms.MessageBoxButtons]::OK,
            [System.Windows.Forms.MessageBoxIcon]::Error
        )
        return
    }

    $selectedItems = @($GridVMs.SelectedRows | ForEach-Object { [string]$_.Cells['VMName'].Value } | Where-Object { -not [string]::IsNullOrWhiteSpace($_) })
    if ($selectedItems.Count -eq 0) {
        Write-TSxUILog -Message 'Enable requested but no VMs were selected.'
        [void][System.Windows.Forms.MessageBox]::Show(
            'Please select one or more virtual machines.',
            'Enable-TSxNestedHyperVVMUI',
            [System.Windows.Forms.MessageBoxButtons]::OK,
            [System.Windows.Forms.MessageBoxIcon]::Warning
        )
        return
    }

    $invalidSelections = @(
        $GridVMs.SelectedRows |
        Where-Object {
            ([string]$_.Cells['IsRunning'].Value -eq 'Yes') -or
            ([string]$_.Cells['HasSnapshot'].Value -eq 'Yes')
        } |
        ForEach-Object { [string]$_.Cells['VMName'].Value }
    )
    if ($invalidSelections.Count -gt 0) {
        $ButtonEnable.Enabled = $false
        Write-TSxUILog -Level 'WARN' -Message ("Enable blocked due to running/snapshot VMs: {0}" -f ($invalidSelections -join ', '))
        [void][System.Windows.Forms.MessageBox]::Show(
            "Cannot enable nested virtualization for selected VM(s) that are running or have snapshots.`r`n`r`nPlease deselect:`r`n$($invalidSelections -join ', ')",
            'Enable-TSxNestedHyperVVMUI',
            [System.Windows.Forms.MessageBoxButtons]::OK,
            [System.Windows.Forms.MessageBoxIcon]::Warning
        )
        return
    }

    $credUser = if ($Script:SelectedCredential) { $Script:SelectedCredential.UserName } else { 'current user' }
    $mode = if ($CheckBoxPSRemoting.Checked) { 'PSRemoting' } else { 'DCOM' }
    Write-TSxUILog -Message ("Enable requested. Host: '{0}', VMs: '{1}', Force: {2}, Credential: '{3}', Mode: '{4}'" -f $TextBox1.Text, ($selectedItems -join ', '), $CheckBoxForce.Checked, $credUser, $mode)

    $LabelStatus.Text = "Running..."
    $Form.Refresh()
    try {
        Write-Host "Running nested Hyper-V configuration on $($TextBox1.Text) via $mode"

        if ($CheckBoxPSRemoting.Checked) {
            # ── PSRemoting path: transfer script content to remote host and execute ──
            if (-not $Script:PSSession -or $Script:PSSession.State -ne 'Opened') {
                throw "No active PSRemoting session. Please Connect first."
            }

            $scriptContent = Get-Content -Path $Script:NestedToolPath -Raw
            $vmNames   = $selectedItems
            $forceFlag = $CheckBoxForce.Checked

            $result = Invoke-Command -Session $Script:PSSession -ScriptBlock {
                param($content, $vms, $force)
                $tmpPath = Join-Path $env:TEMP ("Enable-TSxNestedHyperVVM_{0}.ps1" -f (Get-Date -Format 'yyyyMMddHHmmss'))
                try {
                    $content | Set-Content -Path $tmpPath -Encoding UTF8 -Force
                    $params = @{ VMName = $vms; Confirm = $false; ErrorAction = 'Stop' }
                    if ($force) { $params['Force'] = $true }
                    & $tmpPath @params
                }
                finally {
                    Remove-Item -Path $tmpPath -Force -ErrorAction SilentlyContinue
                }
            } -ArgumentList $scriptContent, $vmNames, $forceFlag

        } else {
            # ── DCOM / ComputerName path (original) ─────────────────────────────
            $invokeParams = @{
                VMName       = $selectedItems
                ComputerName = $TextBox1.Text
                Confirm      = $false
                ErrorAction  = 'Stop'
            }
            if ($CheckBoxForce.Checked) {
                $invokeParams['Force'] = $true
            }
            if ($Script:SelectedCredential) {
                $invokeParams['Credential'] = $Script:SelectedCredential
            }

            $result = & $Script:NestedToolPath @invokeParams
        }

        $okCount   = @($result | Where-Object { $_.Status -eq 'Success' }).Count
        $failCount = @($result | Where-Object { $_.Status -ne 'Success' }).Count
        Write-TSxUILog -Message ("Enable completed. Success: {0}, Other: {1}" -f $okCount, $failCount)

        foreach ($item in ($result | Where-Object { $_.Status -ne 'Success' })) {
            Write-TSxUILog -Level 'WARN' -Message ("VM '{0}' result: {1} - {2}" -f $item.VMName, $item.Status, $item.Message)
        }

        $LabelStatus.Text = "Done: $okCount ok, $failCount other"
        $summary = "Done.`r`nSuccess: $okCount`r`nOther: $failCount"
        [void][System.Windows.Forms.MessageBox]::Show(
            $summary,
            'Enable-TSxNestedHyperVVMUI',
            [System.Windows.Forms.MessageBoxButtons]::OK,
            [System.Windows.Forms.MessageBoxIcon]::Information
        )

        Connect-TSxUI
    }
    catch {
        $LabelStatus.Text = "Error"
        Write-TSxUILog -Level 'ERROR' -Message ("Enable operation failed. Host: '{0}'. Exception: {1}" -f $TextBox1.Text, $_.Exception.ToString())
        [void][System.Windows.Forms.MessageBox]::Show(
            "Enable operation failed.`r`n$($_.Exception.Message)",
            'Enable-TSxNestedHyperVVMUI',
            [System.Windows.Forms.MessageBoxButtons]::OK,
            [System.Windows.Forms.MessageBoxIcon]::Error
        )
    }
}

function Invoke-TSxUIElevate {
    Write-TSxUILog -Message 'Elevate requested. Relaunching as administrator.'
    try {
        Start-Process -FilePath 'powershell.exe' `
            -ArgumentList ('-NoProfile -ExecutionPolicy Bypass -File "{0}"' -f $PSCommandPath) `
            -Verb RunAs
        $Form.Close()
    }
    catch {
        Write-TSxUILog -Level 'ERROR' -Message ("Elevation failed. Exception: {0}" -f $_.Exception.ToString())
        [void][System.Windows.Forms.MessageBox]::Show(
            "Failed to relaunch as administrator.`r`n$($_.Exception.Message)",
            'Enable-TSxNestedHyperVVMUI',
            [System.Windows.Forms.MessageBoxButtons]::OK,
            [System.Windows.Forms.MessageBoxIcon]::Error
        )
    }
}

#region gui events
$ButtonConnect.Add_Click({ Connect-TSxUI })
$ButtonCredential.Add_Click({ Manage-TSxUICredential })
$ButtonClose.Add_Click({ Close-TSxUI })
$ButtonEnable.Add_Click({ Enable-TSxUI })
$ButtonElevate.Add_Click({ Invoke-TSxUIElevate })
$GridVMs.Add_SelectionChanged({ Update-TSxUIEnableButtonState })
$Form.Add_FormClosed({
    if ($Script:PSSession) {
        Remove-PSSession -Session $Script:PSSession -ErrorAction SilentlyContinue
        $Script:PSSession = $null
    }
    Write-TSxUILog -Message "$Script:UIToolName closed."
})
#endregion
Write-TSxUILog -Message ("UI form displayed. Log: {0}" -f $Script:UILogFile)
[void]$Form.ShowDialog()